"use client";
import { ApiRute } from "@/url/ApiRoute";
import { API_BASE_URL } from "@/url/BaseURL";
import { useParams } from "next/navigation";
import React, { useEffect, useState } from "react";

// ✅ Safe date formatter
const formatDate = (dateStr) => {
  const d = new Date(dateStr);
  const day = d.getDate().toString().padStart(2, "0");
  const month = (d.getMonth() + 1).toString().padStart(2, "0");
  const year = d.getFullYear();
  return `${day}/${month}/${year}`;
};

export default function UserDashboard() {
  const { details } = useParams();
  const [subscriptionTab, setSubscriptionTab] = useState("current");
  const [serviceTab, setServiceTab] = useState("current");

  const [user, setUser] = useState({
    name: "Kush Qurilo",
    email: "kush@example.com",
    paidSubscriptions: [
      {
        paidForMonth: "October 2025",
        paidForDueDate: "2025-10-31",
        amount: 1000,
        gst: 18,
        totalAmount: 1180,
        status: "paid",
      },
      {
        paidForMonth: "September 2025",
        paidForDueDate: "2025-09-30",
        amount: 1500,
        gst: 18,
        totalAmount: 1770,
        status: "paid",
      },
    ],
    unpaidSubscriptions: [], // will load from API
    paidServices: [
      {
        paidForMonth: "October 2025",
        emiNumber: 1,
        emiAmount: 299,
        dueDate: "2025-10-25",
        status: "paid",
      },
      {
        paidForMonth: "September 2025",
        emiNumber: 2,
        emiAmount: 199,
        dueDate: "2025-10-20",
        status: "paid",
      },
    ],
    unpaidServices: [
      {
        paidForMonth: "November 2025",
        emiNumber: 1,
        emiAmount: 250,
        dueDate: "2025-11-30",
        status: "pending",
      },
      {
        paidForMonth: "December 2025",
        emiNumber: 1,
        emiAmount: 300,
        dueDate: "2025-12-15",
        status: "pending",
      },
    ],
  });

  const subscriptionsToShow =
    subscriptionTab === "paid"
      ? user.paidSubscriptions
      : user.unpaidSubscriptions;
  const servicesToShow =
    serviceTab === "paid" ? user.paidServices : user.unpaidServices;

  const getStatusClass = (status) => {
    if (status === "paid") return "bg-green-100 text-green-600";
    if (status === "pending") return "bg-yellow-100 text-yellow-600";
    return "bg-gray-200 text-gray-500";
  };

  // ✅ Mark subscription as paid (frontend + backend)
  const subscriptionMarkAsPaid = async (subscription) => {
    try {
      // Call backend API
      const res = await fetch(
        `${API_BASE_URL}${ApiRute.subscription.markaspaid}`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            subscriptionId: subscription._id,
            paymentMode: "UPI",
          }),
        }
      );
      const data = await res.json();
      if (data.success) {
        alert("Subscription marked as paid!");

        // Update frontend state: move subscription to paidSubscriptions
        const updatedPaid = [
          ...user.paidSubscriptions,
          { ...subscription, status: "paid" },
        ];
        const updatedUnpaid = user.unpaidSubscriptions.filter(
          (s) => s._id !== subscription._id
        );
        setUser({
          ...user,
          paidSubscriptions: updatedPaid,
          unpaidSubscriptions: updatedUnpaid,
        });
      } else {
        alert(data.message || "Failed to mark as paid.");
      }
    } catch (err) {
      console.error(err);
      alert("Error marking subscription as paid.");
    }
  };

  // ✅ Mark service as paid (frontend only)
  const checkServicePayment = (svcIndex) => {
    const updatedPaid = [
      ...user.paidServices,
      { ...user.unpaidServices[svcIndex], status: "paid" },
    ];
    const updatedUnpaid = user.unpaidServices.filter(
      (_, idx) => idx !== svcIndex
    );
    setUser({
      ...user,
      paidServices: updatedPaid,
      unpaidServices: updatedUnpaid,
    });
    alert(
      `Service for ${user.unpaidServices[svcIndex].paidForMonth} marked as PAID.`
    );
  };

  // ✅ Fetch unpaid subscriptions from API
  const fetchMonthlySubscription = async () => {
    try {
      const response = await fetch(
        `${API_BASE_URL}${ApiRute.subscription.singerSubscription}/${details}`,
        { method: "GET", headers: { "content-type": "application/json" } }
      );
      const result = await response.json();
      if (result.data && result.data.length > 0) {
        const unpaidSubs = result.data.map((sub) => ({
          ...sub,
          paidForMonth: new Date(sub.dueDate).toLocaleString("default", {
            month: "long",
            year: "numeric",
          }),
          status: sub.isPaid ? "paid" : "pending",
        }));
        setUser((prev) => ({ ...prev, unpaidSubscriptions: unpaidSubs }));
      } else {
        setUser((prev) => ({ ...prev, unpaidSubscriptions: [] }));
      }
    } catch (err) {
      console.error(err);
      alert("Error fetching subscription data.");
    }
  };

  useEffect(() => {
    fetchMonthlySubscription();
  }, [details]);

  return (
    <div className="min-h-screen flex justify-center items-center bg-gray-100 p-6">
      <div className="max-w-6xl w-full flex flex-col space-y-8 justify-center rounded-xl bg-white p-5">
        {/* Main content: left-right layout */}
        <div className="flex flex-col md:flex-row gap-6">
          {/* Left: Subscriptions */}
          <div className="flex-1 flex flex-col">
            <h3 className="text-xl font-semibold text-gray-800 mb-3">
              Monthly Subscriptions
            </h3>
            <ul className="flex border-b mb-3">
              <li
                className={`cursor-pointer px-4 py-2 ${
                  subscriptionTab === "current"
                    ? "border-b-2 border-blue-600 font-semibold text-blue-600"
                    : "text-gray-500 hover:text-blue-600"
                }`}
                onClick={() => setSubscriptionTab("current")}
              >
                Current
              </li>
              <li
                className={`cursor-pointer px-4 py-2 ${
                  subscriptionTab === "paid"
                    ? "border-b-2 border-blue-600 font-semibold text-blue-600"
                    : "text-gray-500 hover:text-blue-600"
                }`}
                onClick={() => setSubscriptionTab("paid")}
              >
                Paid
              </li>
            </ul>

            <div className="flex-1 max-h-[500px] overflow-y-auto space-y-3 border border-gray-200 rounded-xl p-4 bg-gray-50">
              {subscriptionsToShow.length === 0 ? (
                <p className="text-gray-500 text-sm">No subscriptions found.</p>
              ) : (
                subscriptionsToShow.map((sub, index) => (
                  <div
                    key={index}
                    className="p-4 border rounded-xl bg-white hover:bg-gray-100 transition flex flex-col relative"
                  >
                    <span
                      className={`absolute top-4 right-4 text-sm font-medium px-3 py-1 rounded-full ${getStatusClass(
                        sub.status
                      )}`}
                    >
                      {sub.status.toUpperCase()}
                    </span>

                    <div>
                      <p className="font-semibold text-gray-800">
                        {sub.paidForMonth}
                      </p>
                      <p className="text-sm text-gray-500">
                        Due Date: {formatDate(sub.paidForDueDate)}
                      </p>
                    </div>

                    <div className="mt-2 grid grid-cols-2 md:grid-cols-3 gap-2 text-sm text-gray-700">
                      <p>Amount: ₹{sub.amount}</p>
                      <p>GST: {sub.gst}%</p>
                      <p>Total: ₹{sub.totalAmount}</p>
                    </div>

                    {/* ✅ Mark as Paid button below subscription info */}
                    {sub.status === "pending" && (
                      <div className="mt-4 flex justify-start">
                        <button
                          onClick={() => subscriptionMarkAsPaid(sub)}
                          className="px-3 py-1 bg-blue-600 text-white rounded hover:bg-green-700 transition text-sm"
                        >
                          Mark as Paid
                        </button>
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Right: Services */}
          <div className="flex-1 flex flex-col">
            <h3 className="text-xl font-semibold mb-3 text-gray-800">
              Services
            </h3>
            <ul className="flex border-b mb-3">
              <li
                className={`cursor-pointer px-4 py-2 ${
                  serviceTab === "current"
                    ? "border-b-2 border-blue-600 font-semibold text-blue-600"
                    : "text-gray-500 hover:text-blue-600"
                }`}
                onClick={() => setServiceTab("current")}
              >
                Current
              </li>
              <li
                className={`cursor-pointer px-4 py-2 ${
                  serviceTab === "paid"
                    ? "border-b-2 border-blue-600 font-semibold text-blue-600"
                    : "text-gray-500 hover:text-blue-600"
                }`}
                onClick={() => setServiceTab("paid")}
              >
                Paid
              </li>
            </ul>

            <div className="flex-1 max-h-[500px] overflow-y-auto space-y-3 border border-gray-200 rounded-xl p-4 bg-gray-50">
              {servicesToShow.length === 0 ? (
                <p className="text-gray-500 text-sm">No services found.</p>
              ) : (
                servicesToShow.map((service, index) => (
                  <div
                    key={index}
                    className="p-4 border rounded-xl bg-white hover:bg-gray-100 transition relative"
                  >
                    <span
                      className={`absolute top-4 right-4 text-sm font-medium px-3 py-1 rounded-full ${getStatusClass(
                        service.status
                      )}`}
                    >
                      {service.status.toUpperCase()}
                    </span>
                    <div>
                      <p className="font-semibold text-gray-800">
                        {service.paidForMonth}
                      </p>
                      <p className="text-sm text-gray-500">
                        EMI Number: {service.emiNumber}
                      </p>
                    </div>
                    <div className="mt-2 grid grid-cols-2 md:grid-cols-3 gap-2 text-sm text-gray-700">
                      <p>EMI Amount: ₹{service.emiAmount}</p>
                      <p>Due Date: {formatDate(service.dueDate)}</p>
                    </div>
                    {service.status === "pending" && (
                      <button
                        onClick={() => checkServicePayment(index)}
                        className="absolute bottom-4 right-4 px-3 py-1 bg-green-600 text-white rounded hover:bg-green-700 transition text-sm"
                      >
                        Mark as Paid
                      </button>
                    )}
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
